&= \frac{(\sqrt{10} - \sqrt{5})(5 \sqrt{2} + 7)}{(5 \sqrt{2} - 7)(5 \sqrt{2} + 7)} \\
&= \boxed{3 \sqrt{5} + 2 \sqrt{10}}.
\end{align*}

